package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testToString() {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set up mock behavior for the toString method
        when(csvFormat.toString()).thenCallRealMethod();
        when(csvFormat.getDelimiter()).thenReturn(',');
        when(csvFormat.isEscapeCharacterSet()).thenReturn(true);
        when(csvFormat.getEscapeCharacter()).thenReturn('\\');
        when(csvFormat.isQuoteCharacterSet()).thenReturn(true);
        when(csvFormat.getQuoteCharacter()).thenReturn('"');
        when(csvFormat.isCommentMarkerSet()).thenReturn(true);
        when(csvFormat.getCommentMarker()).thenReturn('#);
        when(csvFormat.isNullStringSet()).thenReturn(true);
        when(csvFormat.getNullString()).thenReturn("NULL");
        when(csvFormat.getRecordSeparator()).thenReturn("\r\n");
        when(csvFormat.getIgnoreEmptyLines()).thenReturn(true);
        when(csvFormat.getIgnoreSurroundingSpaces()).thenReturn(false);
        when(csvFormat.getIgnoreHeaderCase()).thenReturn(true);
        when(csvFormat.getSkipHeaderRecord()).thenReturn(false);
        when(csvFormat.getHeaderComments()).thenReturn(new String[]{"comment1", "comment2"});
        when(csvFormat.getHeader()).thenReturn(new String[]{"header1", "header2"});

        // Expected toString result
        String expected = "Delimiter=<,> Escape=<\\> QuoteChar=<\"> CommentStart=<#> NullString=<NULL> RecordSeparator=<\r\n> EmptyLines:ignored IgnoreHeaderCase:ignored SkipHeaderRecord:false HeaderComments:[comment1, comment2] Header:[header1, header2]";

        // Test the toString method
        assertEquals(expected, csvFormat.toString());
    }
}
